export const validarCPF = (cpf) => {
  if (cpf.length !== 11 || /^(\d)\1{10}$/.test(cpf)) return false;
  
  // Cálculo do primeiro dígito verificador
  let soma = 0;
  for (let i = 0; i < 9; i++) {
    soma += parseInt(cpf.charAt(i)) * (10 - i);
  }
  let resto = soma % 11;
  let digitoVerificador1 = resto < 2 ? 0 : 11 - resto;
  
  // Cálculo do segundo dígito verificador
  soma = 0;
  for (let i = 0; i < 10; i++) {
    soma += parseInt(cpf.charAt(i)) * (11 - i);
  }
  resto = soma % 11;
  let digitoVerificador2 = resto < 2 ? 0 : 11 - resto;
  
  return (
    digitoVerificador1 === parseInt(cpf.charAt(9)) &&
    digitoVerificador2 === parseInt(cpf.charAt(10))
  );
};

export const validarCNPJ = (cnpj) => { 
  // console.log("CNPJ recebido para validação:", cnpj); // Linha de depuração, manter comentada ou remover para produção
  if (typeof cnpj !== 'string') cnpj = String(cnpj); // Garante que cnpj é string
  
  cnpj = cnpj.replace(/\D/g, ''); // Remove caracteres não numéricos, caso a função seja chamada com cnpj formatado

  if (cnpj.length !== 14 || /^(\d)\1{13}$/.test(cnpj)) {
    // console.log("Falha no teste inicial de formato/repetição");
    return false;
  }

  // Cálculo do primeiro dígito verificador (DV1)
  // Pesos para DV1: 5, 4, 3, 2, 9, 8, 7, 6, 5, 4, 3, 2 (para os 12 primeiros dígitos do CNPJ)
  let numerosParaDV1 = cnpj.substring(0, 12);
  let somaDV1 = 0;
  let peso = 5;
  for (let i = 0; i < 12; i++) {
    somaDV1 += parseInt(numerosParaDV1.charAt(i)) * peso;
    peso--;
    if (peso < 2) {
      peso = 9;
    }
  }
  let dv1Calculado = somaDV1 % 11 < 2 ? 0 : 11 - (somaDV1 % 11);
  // console.log("DV1 Calculado:", dv1Calculado, "DV1 Esperado (cnpj.charAt(12)):", parseInt(cnpj.charAt(12)));

  if (dv1Calculado !== parseInt(cnpj.charAt(12))) {
    // console.log("Validação do DV1 falhou.");
    return false;
  }

  // Cálculo do segundo dígito verificador (DV2)
  // Pesos para DV2: 6, 5, 4, 3, 2, 9, 8, 7, 6, 5, 4, 3, 2 (para os 12 primeiros dígitos + DV1)
  let numerosParaDV2 = cnpj.substring(0, 13); // Inclui o DV1 correto
  let somaDV2 = 0;
  peso = 6; // Reinicia o peso para o cálculo do DV2
  for (let i = 0; i < 13; i++) {
    somaDV2 += parseInt(numerosParaDV2.charAt(i)) * peso;
    peso--;
    if (peso < 2) {
      peso = 9;
    }
  }
  let dv2Calculado = somaDV2 % 11 < 2 ? 0 : 11 - (somaDV2 % 11);
  // console.log("DV2 Calculado:", dv2Calculado, "DV2 Esperado (cnpj.charAt(13)):", parseInt(cnpj.charAt(13)));

  if (dv2Calculado !== parseInt(cnpj.charAt(13))) {
    // console.log("Validação do DV2 falhou.");
    return false;
  }

  // console.log("CNPJ Válido pela função!");
  return true;
};

export const validarCPFCNPJ = (doc) => {
  const docLimpo = doc.replace(/\D/g, '');

  if (docLimpo.length === 11) {
    if (!validarCPF(docLimpo)) throw new Error('CPF inválido');
  } else if (docLimpo.length === 14) {
    if (!validarCNPJ(docLimpo)) throw new Error('CNPJ inválido');
  } else {
    throw new Error('Documento deve ter 11 (CPF) ou 14 (CNPJ) dígitos');
  }

  return true;
};

export const validarCelular = (celular) => {
  if (!celular || celular.trim() === '') {
    throw new Error('Celular é obrigatório');
  }

  const nums = celular.replace(/\D/g, '');
  if (nums.length < 10 || nums.length > 11) {
    throw new Error('Celular deve ter 10 ou 11 dígitos (após DDD)');
  }
  return true;
};

export const formatCPForCNPJ = (cpfCnpj) => {
  if (!cpfCnpj) return '';
  const str = cpfCnpj.toString().replace(/\D/g, '');
  
  if (str.length === 11) {
    return str.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
  } else if (str.length === 14) {
    return str.replace(/(\d{2})(\d{3})(\d{3})(\d{4})(\d{2})/, '$1.$2.$3/$4-$5');
  }
  return str;
};

export const formatCelular = (celular) => {
  if (!celular) return '';
  const nums = celular.toString().replace(/\D/g, '');
  return nums.length === 11 ? 
    nums.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3') :
    nums.replace(/(\d{2})(\d{4})(\d{4})/, '($1) $2-$3');
};
